#!/usr/bin/perl
use strict;
use warnings;
use Storable qw(nstore retrieve lock_nstore lock_retrieve);
use CGI;
use CGI::Cookie;
use Digest::SHA qw(sha256_hex);
use File::Spec;
use Fcntl qw(:flock);

# Configuration
my $SESSION_DIR     = '/tmp';
my $SESSION_PREFIX  = 'sess_';
my $SESSION_COOKIE  = 'PERL_SESSION_ID';
my $SESSION_EXPIRE  = 3600;  # 1 hour in seconds

# --- Session Management Package ---
package Session;

sub new {
    my ($class, %opts) = @_;
    my $self = bless {
        session_dir    => $opts{session_dir}    || $SESSION_DIR,
        session_prefix => $opts{session_prefix} || $SESSION_PREFIX,
        cookie_name    => $opts{cookie_name}    || $SESSION_COOKIE,
        expire         => $opts{expire}         || $SESSION_EXPIRE,
        cgi            => $opts{cgi}            || CGI->new(),
        session_id     => undef,
        data           => {},
        is_new         => 0,
        modified       => 0,
    }, $class;

    $self->_init();
    return $self;
}

sub _init {
    my ($self) = @_;

    # Ensure session directory exists
    unless (-d $self->{session_dir}) {
        mkdir $self->{session_dir}, 0700
            or die "Cannot create session directory $self->{session_dir}: $!";
    }

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    if ($cookies{$self->{cookie_name}}) {
        my $candidate_id = $cookies{$self->{cookie_name}}->value;

        # Validate session ID format (only hex characters allowed)
        if ($candidate_id && $candidate_id =~ /^[a-f0-9]{64}$/) {
            $self->{session_id} = $candidate_id;
        }
    }

    # Attempt to load existing session
    if ($self->{session_id}) {
        my $loaded = $self->_load_session();
        unless ($loaded) {
            # Session file missing or corrupt; create new session
            $self->_create_new_session();
        }
    } else {
        $self->_create_new_session();
    }
}

sub _generate_session_id {
    my ($self) = @_;
    my $random_data = join('',
        time(),
        $$,
        rand(999999999),
        (exists $ENV{REMOTE_ADDR} ? $ENV{REMOTE_ADDR} : ''),
        (exists $ENV{HTTP_USER_AGENT} ? $ENV{HTTP_USER_AGENT} : ''),
    );
    return Digest::SHA::sha256_hex($random_data . rand());
}

sub _session_file {
    my ($self) = @_;
    return File::Spec->catfile(
        $self->{session_dir},
        $self->{session_prefix} . $self->{session_id}
    );
}

sub _create_new_session {
    my ($self) = @_;
    $self->{session_id} = $self->_generate_session_id();
    $self->{data} = {
        _created  => time(),
        _accessed => time(),
        _expires  => time() + $self->{expire},
    };
    $self->{is_new}    = 1;
    $self->{modified}  = 1;
    $self->_save_session();
}

sub _load_session {
    my ($self) = @_;
    my $file = $self->_session_file();

    return 0 unless -f $file;

    eval {
        $self->{data} = lock_retrieve($file);
    };
    if ($@ || !$self->{data}) {
        warn "Failed to load session $self->{session_id}: $@";
        return 0;
    }

    # Check expiration
    if (exists $self->{data}{_expires} && $self->{data}{_expires} < time()) {
        $self->destroy();
        return 0;
    }

    # Update last accessed time
    $self->{data}{_accessed} = time();
    $self->{data}{_expires}  = time() + $self->{expire};
    $self->{modified} = 1;

    return 1;
}

sub _save_session {
    my ($self) = @_;
    my $file = $self->_session_file();

    eval {
        lock_nstore($self->{data}, $file);
    };
    if ($@) {
        warn "Failed to save session $self->{session_id}: $@";
        return 0;
    }

    # Set file permissions to owner-only
    chmod 0600, $file;
    $self->{modified} = 0;
    return 1;
}

# Get a session value
sub get {
    my ($self, $key) = @_;
    return unless defined $key;
    return $self->{data}{$key};
}

# Set a session value
sub set {
    my ($self, $key, $value) = @_;
    return unless defined $key;
    $self->{data}{$key} = $value;
    $self->{modified} = 1;
    return $value;
}

# Delete a session value
sub delete {
    my ($self, $key) = @_;
    return unless defined $key;
    my $old = delete $self->{data}{$key};
    $self->{modified} = 1;
    return $old;
}

# Check if a key exists
sub exists {
    my ($self, $key) = @_;
    return exists $self->{data}{$key};
}

# Get all user keys (excluding internal keys)
sub keys {
    my ($self) = @_;
    return grep { !/^_/ } keys %{$self->{data}};
}

# Get session ID
sub id {
    my ($self) = @_;
    return $self->{session_id};
}

# Check if session is new
sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

# Get the session cookie for HTTP header
sub cookie {
    my ($self) = @_;
    my $cookie = CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id},
        -expires  => '+' . $self->{expire} . 's',
        -path     => '/',
        -httponly  => 1,
        -secure   => ($ENV{HTTPS} ? 1 : 0),
        -samesite => 'Strict',
    );
    return $cookie;
}

# Flush/save session data to disk
sub flush {
    my ($self) = @_;
    if ($self->{modified}) {
        return $self->_save_session();
    }
    return 1;
}

# Destroy the session
sub destroy {
    my ($self) = @_;
    my $file = $self->_session_file();
    unlink $file if -f $file;
    $self->{data}     = {};
    $self->{modified} = 0;
    return 1;
}

# Clean up expired sessions (class method)
sub cleanup_expired {
    my ($class_or_self, %opts) = @_;
    my $dir    = $opts{session_dir}    || $SESSION_DIR;
    my $prefix = $opts{session_prefix} || $SESSION_PREFIX;
    my $expire = $opts{expire}         || $SESSION_EXPIRE;

    my $count = 0;
    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory $dir: $!";
        return 0;
    };

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /^\Q$prefix\E[a-f0-9]{64}$/;
        my $file = File::Spec->catfile($dir, $entry);

        eval {
            my $data = lock_retrieve($file);
            if ($data && ref $data eq 'HASH') {
                if (exists $data->{_expires} && $data->{_expires} < time()) {
                    unlink $file;
                    $count++;
                }
            }
        };
        if ($@) {
            # Corrupt file, remove it
            unlink $file;
            $count++;
        }
    }
    closedir($dh);
    return $count;
}

# Auto-save on object destruction
sub DESTROY {
    my ($self) = @_;
    $self->flush() if $self->{modified};
}

